code = """import json
import pandas as pd

# Load the full list of NYSE non-ETF stocks and their names
file_path_names = locals()['var_function-call-10853579971891121046']
with open(file_path_names, 'r') as f:
    nyse_stocks_info = json.load(f)

nyse_symbols_and_names = {symbol: info for symbol, info in nyse_stocks_info.items()}

# Existing processed results from previous steps
results_list = locals()['var_function-call-14892611708142278534']

# Process BDXA data
bdxa_data_path = locals()['var_function-call-17872404958242835710']
with open(bdxa_data_path, 'r') as f:
    bdxa_data = json.load(f)

up_days_bdxa = 0
down_days_bdxa = 0
for record in bdxa_data:
    if float(record['Close']) > float(record['Open']):
        up_days_bdxa += 1
    elif float(record['Close']) < float(record['Open']):
        down_days_bdxa += 1

result_bdxa = {
    "Symbol": "BDXA",
    "Company Name": nyse_symbols_and_names["BDXA"],
    "Up Days": up_days_bdxa,
    "Down Days": down_days_bdxa,
    "Difference": up_days_bdxa - down_days_bdxa
}

# Aggregate all results
results_list.append(result_bdxa)

# Sort the current list of results and take the top 5
results_list = sorted(results_list, key=lambda x: x['Difference'], reverse=True)

print("__RESULT__:")
print(json.dumps(results_list[:5]))"""

